import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小动物- 鸟","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 鸟.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 鸟.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 鸟.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"小动物-鸟",tabindex:"-1"},[p("小动物- 鸟 "),r("a",{class:"header-anchor",href:"#小动物-鸟","aria-label":'Permalink to "小动物- 鸟"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="小动物-鸟-1" tabindex="-1">小动物- 鸟 <a class="header-anchor" href="#小动物-鸟-1" aria-label="Permalink to &quot;小动物- 鸟&quot;">​</a></h1><p>小鸟（首先说一下，不能飞！不能飞！不能飞！）<br> 无支线随从<br> 250分<br> 动物种类：鸟类动物<br> 鸟是脊椎动物亚门的一纲，是所有鸟类动物的统称。 身体呈流线型，皮肤薄而有韧性；体表覆羽毛，一般前肢变成翼，有的种类翼退化；胸肌发达；直肠短；心脏有两心房和两心室，体温恒定。在人工饲养条件下，大型鸟类寿命3050年，中等类型鸟类寿命2030年，小型鸟类寿命1015年。<br> 随从外貌：根据自我喜欢去选择一种鸟，然后把对于自己的小鸟的外貌描述填入这里<br> 基础外貌：3<br> 基础体型：1-4（根据你自己选择的鸟类体型自己进行填写）<br> 随从属性：<br> 生理属性<br> 力量：1<br> 敏捷：5<br> 耐力：3<br> 心智属性<br> 智力：1<br> 感知：5<br> 决心：1<br> 互动属性<br> 风度：3<br> 操控：3<br> 沉着：1</p><p>技能<br> 生理系<br> 运动3<br> 专业：反射3 平衡1<br> 求生1<br> 专业：强韧1<br> 射击1<br> 专业：<br> 武技1<br> 专业：爪1</p><p>心智系<br> 学识1<br> 专业：爪精通1<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注1<br> 专业：意志1</p><p>互动系<br> 洞察3<br> 专业：侦查3<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【1】+敏捷【5】+体积【1-4】+每1点敏捷上的附加获得3移动速度）=7-10（根据你选择的鸟类大小进行填写）<br> 先攻 （敏捷【5】+沉着【1】）= 6<br> 防御 （敏捷感知的平均值【4】+较高者的附加成功【】）=4<br> 生命值 （耐力【3】+体积【1-4】+耐力附加【 】×5）=4-7（根据你选的鸟类大小进行填写）<br> 意志力池 （决心【1】+沉着【1】+决心附加【 】×2）=2<br> 意志 （决心【1】+专注+意志【2】）= 3<br> 反射 （敏捷【5】+运动+反射【6】）= 11+1<br> 强韧 （耐力【3】+生存+强韧【2】）= 5<br> 侦查 （感知【5】+洞察+侦查【6+1】）= 11+1<br> 敏感范围 （感知【5】*20米+感知上的附加成功【 1】*20米）=120米</p><p>攻击预设：6<br> 基础DP：3（力量）+1（武技）+1（牙击）+1（牙精通）=6<br> 非常态项：<br> 破防效果：<br> 附加成功：<br> 非常态项：<br> 攻击特殊效果：</p><p>防御预设：<br> 基础防御：4<br> 附加成功：无<br> 额外效果：<br> 防御类型：<br> 附加成功：<br> 额外效果：</p><p>豁免项：<br> 意志豁免：3<br> 附加成功：<br> 反射豁免：11<br> 附加成功：1<br> 强韧豁免：5<br> 附加成功：</p><p>免疫项：</p><p>专长：</p><p>装备位：<br> 头部-面具/头盔（会被小鸟带在头上但是因为脸部无法带面具所以一般面具无法佩戴）<br> 颈部-护符 （会变成项链吊坠项圈这种类似在小鸟的脖子上）<br> 上肢-爪子 （给爪子上特殊的武装，但是不能持握武器）<br> 下肢-鞋袜 （给小鸟的爪子穿上鞋袜但是因此会跟爪子产生冲突）</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
